#include <bits/stdc++.h>
using namespace std;
int n;
string s="";
void dfs(int x){
	cout<<s<<'\n';
	if(x==4){
		swap(s[3],s[8]),swap(s[4],s[9]);
		cout<<s<<'\n';
		swap(s[3],s[7]),swap(s[4],s[8]);
		cout<<s<<'\n';
		swap(s[1],s[7]),swap(s[2],s[8]);
		cout<<s<<'\n';
		swap(s[1],s[6]),swap(s[2],s[7]);
		cout<<s<<'\n';
		swap(s[0],s[6]),swap(s[1],s[7]);
		cout<<s<<'\n';
	}else{
		swap(s[x-1],s[2*x]),swap(s[x],s[2*x+1]);
		cout<<s<<'\n';
		swap(s[x-1],s[2*x-2]),swap(s[x],s[2*x-1]);
		dfs(x-1);
	}
}
int main(){
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
		s+="o";
	for(int i=1;i<=n;i++)
		s+="*";
	s+="--";
	dfs(n); 
	return 0;
}
